use std::collections::BTreeMap;
use std::error::Error;

use super::rig_client;

// Generated by build.rs from src/rig/r-versions.json:
// - EMBEDDED_MINOR_RELEASES_FETCHED_AT: &str
// - EMBEDDED_MINOR_RELEASES: &[MinorRelease]
include!(concat!(env!("OUT_DIR"), "/r_version_releases.rs"));

struct MinorRelease {
    major: u64,
    minor: u64,
    date: &'static str,
}

#[derive(serde::Deserialize)]
struct AvailableRelease {
    version: String,
    date: Option<String>,
}

pub(crate) fn latest_minor_version_on(exclude_newer: &str) -> Result<String, Box<dyn Error>> {
    let mut version = latest_embedded_minor_version_on(exclude_newer);

    if exclude_newer > EMBEDDED_MINOR_RELEASES_FETCHED_AT {
        match latest_available_minor_version_on(exclude_newer) {
            Ok(Some(discovered)) => {
                version = Some(
                    version
                        .map(|embedded| embedded.max(discovered))
                        .unwrap_or(discovered),
                );
            }
            Ok(None) => {}
            Err(err) => {
                if version.is_none() {
                    return Err(err);
                }
            }
        }
    }

    let (major, minor) = version.ok_or_else(|| {
        format!("could not resolve latest R minor version available before or on {exclude_newer}")
    })?;

    Ok(format!("{major}.{minor}"))
}

fn latest_embedded_minor_version_on(exclude_newer: &str) -> Option<(u64, u64)> {
    EMBEDDED_MINOR_RELEASES
        .iter()
        .filter(|release| release.date <= exclude_newer)
        .max_by_key(|release| (release.major, release.minor))
        .map(|release| (release.major, release.minor))
}

fn latest_available_minor_version_on(
    exclude_newer: &str,
) -> Result<Option<(u64, u64)>, Box<dyn Error>> {
    let json = String::from_utf8(rig_client::output(&["available", "--all", "--json"])?)
        .map_err(|e| format!("`rig available --all --json` returned non-UTF-8 output: {e}"))?;
    let available: Vec<AvailableRelease> = serde_json::from_str(&json)
        .map_err(|e| format!("failed to parse `rig available --all --json` JSON: {e}"))?;

    let mut first_release_dates = BTreeMap::new();
    for release in available {
        let Some((major, minor, _patch)) = version_parts(&release.version) else {
            continue;
        };
        if major < 3 {
            continue;
        }
        let Some(date) = release.date.as_deref().and_then(iso_date_prefix) else {
            continue;
        };
        first_release_dates
            .entry((major, minor))
            .and_modify(|previous: &mut String| {
                if date < previous.as_str() {
                    *previous = date.to_string();
                }
            })
            .or_insert_with(|| date.to_string());
    }

    Ok(first_release_dates
        .into_iter()
        .filter(|(_, date)| date.as_str() <= exclude_newer)
        .map(|(version, _)| version)
        .max())
}

fn version_parts(value: &str) -> Option<(u64, u64, u64)> {
    let mut parts = value.split('.');
    let major = parts.next()?.parse().ok()?;
    let minor = parts.next()?.parse().ok()?;
    let patch = parts.next()?.parse().ok()?;
    if parts.next().is_some() {
        return None;
    }
    Some((major, minor, patch))
}

fn iso_date_prefix(value: &str) -> Option<&str> {
    let date = value.get(..10)?;
    if is_iso_date(date) {
        Some(date)
    } else {
        None
    }
}

fn is_iso_date(value: &str) -> bool {
    let bytes = value.as_bytes();
    bytes.len() == 10
        && bytes[0].is_ascii_digit()
        && bytes[1].is_ascii_digit()
        && bytes[2].is_ascii_digit()
        && bytes[3].is_ascii_digit()
        && bytes[4] == b'-'
        && bytes[5].is_ascii_digit()
        && bytes[6].is_ascii_digit()
        && bytes[7] == b'-'
        && bytes[8].is_ascii_digit()
        && bytes[9].is_ascii_digit()
}
